  margin: 0;
  padding: 0;
  box-sizing: border-box;
  font-family: "Segoe UI", sans-serif;
}

body {
  background: #0f172a;
}

.welcome-container {
  width: 100%;
  min-height: 100vh;
  background: linear-gradient(135deg, #0f172a, #1e293b);
  color: white;
}

.overlay {
  width: 100%;
  min-height: 100vh;
  padding: 30px 8%;
}

/* Navbar */

.navbar {
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.logo h2 {
  font-size: 32px;
  color: #ff9800;
}

.navbar ul {
  display: flex;
  gap: 35px;
  list-style: none;
}

.navbar ul li a {
  text-decoration: none;
  color: white;
  font-size: 17px;
  transition: .3s;
}

.navbar ul li a:hover {
  color: #ff9800;
}

/* Hero */

.hero {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-top: 70px;
  gap: 60px;
}

.hero-left {
  flex: 1;
}

.hero-left h1 {
  font-size: 55px;
  line-height: 1.2;
}

.hero-left span {
  color: #ff9800;
}

.hero-left p {
  margin-top: 25px;
  color: #d1d5db;
  font-size: 18px;
  line-height: 30px;
}

/* Buttons */

.buttons {
  margin-top: 40px;
  display: flex;
  gap: 20px;
}

.admin-btn,
.employee-btn {
  text-decoration: none;
  padding: 15px 35px;
  border-radius: 10px;
  font-size: 18px;
  transition: .3s;
}

.admin-btn {
  background: #ff9800;
  color: white;
}

.employee-btn {
  border: 2px solid #ff9800;
  color: #ff9800;
}

.admin-btn:hover {
  background: #ff6f00;
  transform: translateY(-3px);
}

.employee-btn:hover {
  background: #ff9800;
  color: white;
  transform: translateY(-3px);
}

/* Right Card */

.hero-right {
  flex: 1;
  display: flex;
  justify-content: center;
}

.card {
  width: 100%;
  max-width: 420px;
  background: rgba(255,255,255,0.08);
  backdrop-filter: blur(12px);
  border-radius: 18px;
  padding: 35px;
  border: 1px solid rgba(255,255,255,0.15);
}

.card h2 {
  color: #ff9800;
  margin-bottom: 25px;
}

.card ul {
  list-style: none;
}

.card ul li {
  margin-bottom: 18px;
  font-size: 17px;
}

/* Features */

.features {
  margin-top: 100px;
}

.features h2 {
  text-align: center;
  font-size: 40px;
  margin-bottom: 50px;
}

.feature-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit,minmax(220px,1fr));
  gap: 25px;
}

.feature-box {
  background: rgba(255,255,255,.08);
  border-radius: 15px;
  text-align: center;
  padding: 35px;
  transition: .3s;
  border: 1px solid rgba(255,255,255,.1);
  font-size: 45px;
}

.feature-box h3 {
  margin-top: 20px;
  font-size: 20px;
}

.feature-box:hover {
  background: #ff9800;
  color: white;
  transform: translateY(-10px);
}

/* Footer */

.footer {
  margin-top: 80px;
  text-align: center;
  padding: 25px;
  color: #cbd5e1;
  border-top: 1px solid rgba(255,255,255,.15);
}

/* Responsive */

@media(max-width:900px){

