    margin:0;
    padding:0;
    box-sizing:border-box;
    font-family:'Segoe UI',sans-serif;
}

body{
    background:#0f172a;
}

.login-container{
    width:100%;
    min-height:100vh;
    display:flex;
    justify-content:center;
    align-items:center;
    padding:20px;
    background:linear-gradient(135deg,#0f172a,#1e293b,#111827);
}

.login-card{
    width:420px;
    max-width:100%;
    background:rgba(255,255,255,0.08);
    backdrop-filter:blur(18px);
    border:1px solid rgba(255,255,255,.15);
    border-radius:20px;
    padding:40px 35px;
    text-align:center;
    box-shadow:0 20px 45px rgba(0,0,0,.35);
}

.login-logo{
    width:90px;
    height:90px;
    object-fit:contain;
    margin-bottom:15px;
}

.login-title{
    display:flex;
    justify-content:center;
    align-items:center;
    gap:10px;
    margin-bottom:8px;
}

.title-icon{
    font-size:28px;
    color:#ff9800;
}

.login-title h2{
    color:#fff;
    font-size:30px;
}

.subtitle{
    color:#cbd5e1;
    margin-bottom:30px;
    font-size:15px;
}

.input-group{
    position:relative;
    margin-bottom:22px;
}

.input-group input{
    width:100%;
    padding:14px 45px;
    border:none;
    outline:none;
    border-radius:10px;
    font-size:16px;
    background:rgba(255,255,255,.12);
    color:white;
}

.input-group input::placeholder{
    color:#d1d5db;
}

.input-icon{
    position:absolute;
    left:15px;
    top:50%;
    transform:translateY(-50%);
    color:#ff9800;
    font-size:18px;
}

.eye-icon{
    position:absolute;
    right:15px;
    top:50%;
    transform:translateY(-50%);
    cursor:pointer;
    color:#ff9800;
    font-size:18px;
}

.login-options{
    display:flex;
    justify-content:space-between;
    align-items:center;
    margin-bottom:25px;
    color:white;
    font-size:14px;
}

.login-options label{
    display:flex;
    align-items:center;
    gap:8px;
}

.login-options input[type="checkbox"]{
    cursor:pointer;
}

.forgot{
    color:#ff9800;
    cursor:pointer;
    transition:.3s;
}

.forgot:hover{
    text-decoration:underline;
}

.login-btn{
    width:100%;
    padding:15px;
    border:none;
    border-radius:10px;
    background:#ff9800;
    color:white;
    font-size:18px;
    font-weight:bold;
    cursor:pointer;
    transition:.3s;
}

.login-btn:hover{
    background:#f57c00;
    transform:translateY(-2px);
}

.bottom-text{
    margin-top:25px;
    color:#cbd5e1;
    font-size:14px;
}

/* Responsive */

@media(max-width:768px){

.login-card{
    width:100%;
    padding:30px 25px;
}

.login-title h2{
    font-size:24px;
}

.login-options{
    flex-direction:column;
    gap:12px;
}

